3228	// reResultRevField extracts the result_rev value from a structured review-error
3229	// event body (one `result_rev=<sha>` line per event, written by
3230	// reviewErrorEventBody). The format is intentionally line-oriented so it
3231	// survives the AppendEvent body cap without losing the rev association.
3232	var reResultRevField = regexp.MustCompile(`(?m)^result_rev=([^\s]+)\s*$`)
3233	var reReviewerIndexField = regexp.MustCompile(`(?m)^reviewer_index=([0-9]+)\s*$`)
3234	
3235	// CountPriorReviewErrors returns the number of `review-error` events already
3236	// recorded against this bead whose body cites the given result_rev. This is
3237	// the FEAT-022 §14 retry counter — it is event-scoped (no separate counter
3238	// field on the bead) so a fresh result_rev naturally resets the count.
3239	func CountPriorReviewErrors(store ExecuteBeadLoopStore, beadID, resultRev string) int {
3240		if resultRev == "" {
3241			return 0
3242		}
3243		events, err := store.Events(beadID)
3244		if err != nil {
3245			return 0
3246		}
3247		n := 0
3248		for _, ev := range events {
3249			if ev.Kind != "review-error" {
3250				continue
3251			}
3252			m := reResultRevField.FindStringSubmatch(ev.Body)
3253			if m == nil {
3254				continue
3255			}
3256			if m[1] == resultRev {
3257				n++
3258			}
3259		}
3260		return n
3261	}
