3263	// CountPriorReviewErrorsForSlot is the two-slot review-group retry counter.
3264	// It scopes retry budget to the candidate result_rev and reviewer slot so a
3265	// malformed/empty/transport failure in one slot does not consume the other
3266	// slot's retry allowance.
3267	func CountPriorReviewErrorsForSlot(store ExecuteBeadLoopStore, beadID, resultRev string, reviewerIndex int) int {
3268		if resultRev == "" {
3269			return 0
3270		}
3271		events, err := store.Events(beadID)
3272		if err != nil {
3273			return 0
3274		}
3275		wantIndex := fmt.Sprintf("%d", reviewerIndex)
3276		n := 0
3277		for _, ev := range events {
3278			if ev.Kind != "review-error" {
3279				continue
3280			}
3281			rev := reResultRevField.FindStringSubmatch(ev.Body)
3282			if rev == nil || rev[1] != resultRev {
3283				continue
3284			}
3285			idx := reReviewerIndexField.FindStringSubmatch(ev.Body)
3286			if idx == nil || idx[1] != wantIndex {
3287				continue
3288			}
3289			n++
3290		}
3291		return n
3292	}
