1	package escalation
2	
3	import (
4		"fmt"
5		"strings"
6	
7		"github.com/DocumentDrivenDX/ddx/internal/bead"
8	)
9	
10	// ExecutionIntentSource identifies where a routing intent came from.
11	type ExecutionIntentSource string
12	
13	const (
14		ExecutionIntentSourceDefault     ExecutionIntentSource = "default"
15		ExecutionIntentSourceHeuristic   ExecutionIntentSource = "heuristic"
16		ExecutionIntentSourceBeadHint    ExecutionIntentSource = "bead_hint"
17		ExecutionIntentSourceCLIPassthru ExecutionIntentSource = "cli"
18	)
19	
20	// ExecutionHint captures the durable bead-level execution intent that DDx
21	// can infer from bead metadata without binding to a concrete harness/provider
22	// pin.
23	type ExecutionHint struct {
24		Source             ExecutionIntentSource
25		RequestedTier      ModelTier
26		SmartJustification string
27		RejectedRoutePins  []string
28	}
29	
30	// ExecutionHintFinding is a single lint finding emitted when bead metadata
31	// carries a durable route pin or a missing smart-tier justification.
32	type ExecutionHintFinding struct {
33		Field   string `json:"field"`
34		Value   string `json:"value,omitempty"`
35		Message string `json:"message"`
36	}
37	
38	// ParseExecutionHint derives the bead's abstract execution intent from its
39	// durable metadata. A tier label wins over heuristics and marks the source as
40	// bead_hint; otherwise the caller should fall back to heuristics/defaults.
41	func ParseExecutionHint(b *bead.Bead) ExecutionHint {
42		if b == nil {
43			return ExecutionHint{Source: ExecutionIntentSourceDefault}
44		}
45	
46		hint := ExecutionHint{
47			Source:             ExecutionIntentSourceHeuristic,
48			RequestedTier:      InferTier(b),
49			SmartJustification: extractSmartJustification(b.Description),
50		}
51		if hint.RequestedTier == "" {
52			hint.Source = ExecutionIntentSourceDefault
53		}
54	
55		for _, raw := range b.Labels {
56			tier, ok := parseTierLabel(raw)
57			if ok {
58				hint.Source = ExecutionIntentSourceBeadHint
59				hint.RequestedTier = tier
60			}
61			if pin, ok := parseDurableRoutePinLabel(raw); ok {
62				hint.RejectedRoutePins = append(hint.RejectedRoutePins, pin)
63			}
64		}
65		if len(b.Extra) > 0 {
66			for k, v := range b.Extra {
67				if pin, ok := parseDurableRoutePinField(k, v); ok {
68					hint.RejectedRoutePins = append(hint.RejectedRoutePins, pin)
69				}
70			}
71		}
72	
73		// The smart-tier justification is only meaningful when the bead explicitly
74		// asks for smart. Heuristic smart inference does not require the authored
75		// SMART JUSTIFICATION section.
76		if hint.RequestedTier != TierSmart {
77			hint.SmartJustification = ""
78		}
79		return hint
80	}
81	
82	// LintExecutionHints returns durable-routing findings for the bead. The lint
83	// surface is intentionally narrow: it rejects smart-tier beads without an
84	// explicit justification and durable model/provider/harness pins that should
85	// stay on one-off CLI flags.
86	func LintExecutionHints(b *bead.Bead) []ExecutionHintFinding {
87		if b == nil {
88			return nil
89		}
90		hint := ParseExecutionHint(b)
91		findings := make([]ExecutionHintFinding, 0, len(hint.RejectedRoutePins)+1)
92	
93		if hint.Source == ExecutionIntentSourceBeadHint && hint.RequestedTier == TierSmart && strings.TrimSpace(hint.SmartJustification) == "" {
94			findings = append(findings, ExecutionHintFinding{
95				Field:   "description",
96				Message: "bead uses tier:smart but has no SMART JUSTIFICATION section",
97			})
98		}
99	
100		for _, pin := range hint.RejectedRoutePins {
101			findings = append(findings, durableRoutePinFinding(b.ID, pin))
102		}
103	
104		return findings
105	}
