107	func parseTierLabel(raw string) (ModelTier, bool) {
108		l := strings.ToLower(strings.TrimSpace(raw))
109		if l == "" {
110			return "", false
111		}
112		tier, ok := strings.CutPrefix(l, "tier:")
113		if !ok {
114			return "", false
115		}
116		switch strings.TrimSpace(tier) {
117		case string(TierSmart):
118			return TierSmart, true
119		case string(TierStandard):
120			return TierStandard, true
121		case string(TierCheap):
122			return TierCheap, true
123		default:
124			return "", false
125		}
126	}
127	
128	func parseDurableRoutePinLabel(raw string) (string, bool) {
129		l := strings.ToLower(strings.TrimSpace(raw))
130		if l == "" {
131			return "", false
132		}
133		switch {
134		case strings.HasPrefix(l, "harness:"),
135			strings.HasPrefix(l, "provider:"),
136			strings.HasPrefix(l, "model:"):
137			if idx := strings.IndexByte(l, ':'); idx > 0 {
138				return l[:idx], true
139			}
140			return l, true
141		default:
142			return "", false
143		}
144	}
145	
146	func parseDurableRoutePinField(key string, value any) (string, bool) {
147		lower := strings.ToLower(strings.TrimSpace(key))
148		switch lower {
149		case "harness", "agent-harness", "execution-harness", "try-harness",
150			"provider", "agent-provider", "execution-provider", "try-provider",
151			"model", "agent-model", "execution-model", "try-model",
152			"model-ref", "agent-model-ref", "execution-model-ref", "try-model-ref":
153			return renderDurableRoutePin(lower, value), true
154		default:
155			return "", false
156		}
157	}
158	
159	func renderDurableRoutePin(key string, value any) string {
160		if value == nil {
161			return key
162		}
163		if s, ok := value.(string); ok && strings.TrimSpace(s) != "" {
164			return fmt.Sprintf("%s=%s", key, s)
165		}
166		return key
167	}
168	
169	func durableRoutePinFinding(beadID, pin string) ExecutionHintFinding {
170		field := pin
171		if idx := strings.IndexByte(pin, '='); idx > 0 {
172			field = pin[:idx]
173		}
174		var message string
175		switch {
176		case strings.Contains(field, "harness"):
177			message = fmt.Sprintf("bead metadata contains %s; durable harness pins are not allowed. Use ddx try %s --harness ... for one-off debugging.", pin, beadID)
178		case strings.Contains(field, "provider"):
179			message = fmt.Sprintf("bead metadata contains %s; durable provider pins are not allowed. Use ddx try %s --provider ... for one-off debugging.", pin, beadID)
180		case strings.Contains(field, "model"):
181			message = fmt.Sprintf("bead metadata contains %s; durable model pins are not allowed. Use ddx try %s --model ... for one-off debugging.", pin, beadID)
182		default:
183			message = fmt.Sprintf("bead metadata contains %s; durable route pins are not allowed.", pin)
184		}
185		return ExecutionHintFinding{
186			Field:   field,
187			Value:   pin,
188			Message: message,
189		}
190	}
191	
192	var smartJustificationPrefix = "SMART JUSTIFICATION:"
193	
194	func extractSmartJustification(description string) string {
195		desc := strings.TrimSpace(description)
196		if desc == "" {
197			return ""
198		}
199	
200		lines := strings.Split(desc, "\n")
201		for i, line := range lines {
202			if strings.TrimSpace(line) != smartJustificationPrefix {
203				continue
204			}
205			var b strings.Builder
206			for _, next := range lines[i+1:] {
207				trimmed := strings.TrimSpace(next)
208				if trimmed == "" {
209					if b.Len() > 0 {
210						b.WriteByte('\n')
211					}
212					continue
213				}
214				if isSectionHeading(trimmed) {
215					break
216				}
217				if b.Len() > 0 {
218					b.WriteByte('\n')
219				}
220				b.WriteString(trimmed)
221			}
222			return strings.TrimSpace(b.String())
223		}
224	
225		return ""
226	}
227	
228	func isSectionHeading(line string) bool {
229		if !strings.HasSuffix(line, ":") {
230			return false
231		}
232		head := strings.TrimSuffix(line, ":")
233		if head == "" {
234			return false
235		}
236		for _, r := range head {
237			switch {
238			case r >= 'A' && r <= 'Z':
239			case r >= '0' && r <= '9':
240			case r == ' ', r == '_', r == '-', r == '/':
241			default:
242				return false
243			}
244		}
245		return true
246	}
