1	package agent
2	
3	import (
4		"context"
5		"math"
6		"reflect"
7		"sort"
8		"sync"
9		"time"
10	
11		agentlib "github.com/easel/fizeau"
12	)
13	
14	const profileSnapshotCacheWindow = 30 * time.Second
15	
16	var (
17		profileSnapshotCacheMu sync.Mutex
18		profileSnapshotCache   = map[agentlib.FizeauService]profileSnapshotCacheEntry{}
19		profileSnapshotNow     = time.Now
20	)
21	
22	type profileSnapshotCacheEntry struct {
23		snap     ProfileSnapshot
24		loadedAt time.Time
25	}
26	
27	// ProfileSnapshot is the fizeau-owned routing vocabulary DDx uses for hidden
28	// lifecycle dispatches. DDx selects policy names from this snapshot; it does
29	// not resolve concrete models.
30	type ProfileSnapshot struct {
31		Profiles []agentlib.PolicyInfo
32		Models   []agentlib.ModelInfo
33	}
34	
35	// LoadProfileSnapshot fetches fizeau profiles and models with short-lived,
36	// stale-on-error memoization keyed to the service identity.
37	func LoadProfileSnapshot(ctx context.Context, svc agentlib.FizeauService) (ProfileSnapshot, error) {
38		if svc == nil {
39			return ProfileSnapshot{}, nil
40		}
41		key, cacheable := profileSnapshotCacheKey(svc)
42		now := profileSnapshotNow()
43	
44		var last profileSnapshotCacheEntry
45		var hadLast bool
46		if cacheable {
47			profileSnapshotCacheMu.Lock()
48			if entry, ok := profileSnapshotCache[key]; ok && now.Sub(entry.loadedAt) < profileSnapshotCacheWindow {
49				snap := cloneProfileSnapshot(entry.snap)
50				profileSnapshotCacheMu.Unlock()
51				return snap, nil
52			}
53			last, hadLast = profileSnapshotCache[key]
54			profileSnapshotCacheMu.Unlock()
55		}
56	
57		profiles, err := svc.ListPolicies(ctx)
58		if err != nil {
59			if hadLast {
60				return cloneProfileSnapshot(last.snap), nil
61			}
62			return ProfileSnapshot{}, err
63		}
64		models, err := svc.ListModels(ctx, agentlib.ModelFilter{})
65		if err != nil {
66			if hadLast {
67				return cloneProfileSnapshot(last.snap), nil
68			}
69			return ProfileSnapshot{}, err
70		}
71	
72		snap := ProfileSnapshot{
73			Profiles: append([]agentlib.PolicyInfo(nil), profiles...),
74			Models:   append([]agentlib.ModelInfo(nil), models...),
75		}
